import { message } from 'antd';
import axios from 'axios';
export function createRequest(interceptors) {
  try {
    var request = axios.create({});
    var func = new Function('message', 'axios', "".concat(interceptors));
    func(message, request);
    return request;
  } catch (e) {
    console.log('createRequest error');
    console.log(e);
    return axios;
  }
}